func nextJSCtx(s []byte, preceding jsCtx) jsCtx {

	s = bytes.TrimRight(s, jsWhitespace)
	if len(s) == 0 {
		return preceding
	}

	switch c, n := s[len(s)-1], len(s); c {
	case '+', '-':

		start := n - 1

		for start > 0 && s[start-1] == c {
			start--
		}
		if (n-start)&1 == 1 {

			return jsCtxRegexp
		}
		return jsCtxDivOp
	case '.':

		if n != 1 && '0' <= s[n-2] && s[n-2] <= '9' {
			return jsCtxDivOp
		}
		return jsCtxRegexp

	case ',', '<', '>', '=', '*', '%', '&', '|', '^', '?':
		return jsCtxRegexp

	case '!', '~':
		return jsCtxRegexp

	case '(', '[':
		return jsCtxRegexp

	case ':', ';', '{':
		return jsCtxRegexp

	case '}':
		return jsCtxRegexp
	default:

		j := n
		for j > 0 && isJSIdentPart(rune(s[j-1])) {
			j--
		}
		if regexpPrecederKeywords[string(s[j:])] {
			return jsCtxRegexp
		}
	}

	return jsCtxDivOp
}
